import{_ as d,o as l,c as a,ag as i}from"./chunks/framework.Vng7Hdlh.js";const c=JSON.parse('{"title":"5. テーブル・フロアマップ管理","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/05-tables.md","filePath":"tenant/05-tables.md"}'),r={name:"tenant/05-tables.md"};function e(o,t,h,s,n,p){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="_5-テーブル・フロアマップ管理" tabindex="-1">5. テーブル・フロアマップ管理 <a class="header-anchor" href="#_5-テーブル・フロアマップ管理" aria-label="Permalink to &quot;5. テーブル・フロアマップ管理&quot;">​</a></h1><p>管理ダッシュボードの「テーブル・フロア」タブでは、店舗のテーブル登録とフロアマップ（リアルタイム状況表示）を管理します。このタブはマネージャー以上のロールで利用できます。</p><h2 id="_5-1-テーブル管理" tabindex="-1">5.1 テーブル管理 <a class="header-anchor" href="#_5-1-テーブル管理" aria-label="Permalink to &quot;5.1 テーブル管理&quot;">​</a></h2><h3 id="テーブル管理画面の構成" tabindex="-1">テーブル管理画面の構成 <a class="header-anchor" href="#テーブル管理画面の構成" aria-label="Permalink to &quot;テーブル管理画面の構成&quot;">​</a></h3><p>「テーブル・フロア」タブ → 「テーブル管理」サブタブを選択すると、登録済みテーブルの一覧が表示されます。</p><p>画面上部には登録テーブル数がカッコ内に表示されます（例：<code>(12)</code>）。テーブルが1つも登録されていない場合は「🪑 テーブルがありません」と表示されます。</p><p>各テーブルは以下の情報を持つカードとして表示されます。</p><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>テーブルコード</td><td>T01、A-1 などの識別コード</td></tr><tr><td>ステータスバッジ</td><td>緑色「有効」/ 赤色「無効」</td></tr><tr><td>座席数</td><td>「4名」のように表示</td></tr><tr><td>QRボタン</td><td>QRコードを表示</td></tr><tr><td>編集ボタン</td><td>テーブル情報を編集</td></tr><tr><td>削除ボタン</td><td>テーブルを削除</td></tr></tbody></table><h3 id="テーブルの追加" tabindex="-1">テーブルの追加 <a class="header-anchor" href="#テーブルの追加" aria-label="Permalink to &quot;テーブルの追加&quot;">​</a></h3><ol><li>「テーブル追加」ボタンをクリックします</li><li>モーダルが開きます（タイトル：「テーブルを追加」）</li><li>以下のフィールドに入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>テーブルコード</td><td>テキスト入力</td><td>✅</td><td>—</td><td>店舗内で一意のコード（例：T01、A-1、カウンター1）。プレースホルダーは「T01」</td></tr><tr><td>座席数</td><td>数値入力</td><td>—</td><td>4</td><td>テーブルの定員人数</td></tr></tbody></table><ol start="4"><li>「保存」ボタンをクリックします</li><li>成功すると「テーブルを追加しました」トーストが表示され、一覧が更新されます</li></ol><p><strong>バリデーション：</strong></p><ul><li>テーブルコードが空の場合：「テーブルコードは必須です」エラー</li><li>同じ店舗に同じコードが既にある場合：「このテーブルコードは既に使用されています」エラー（HTTPステータス409）</li></ul><p><strong>テーブル作成時に自動的に行われること：</strong></p><ul><li>UUID形式の一意なIDが自動生成されます</li><li>セッショントークン（64文字のランダムな16進数文字列）が自動生成されます</li><li>セッショントークンの有効期限が4時間後に設定されます</li><li>フロアマップ用の初期位置（X=0, Y=0）、サイズ（幅80px, 高さ80px）、形状（四角形）、フロア（1F）が自動設定されます</li></ul><h3 id="テーブルの編集" tabindex="-1">テーブルの編集 <a class="header-anchor" href="#テーブルの編集" aria-label="Permalink to &quot;テーブルの編集&quot;">​</a></h3><ol><li>一覧で対象テーブルの<strong>編集ボタン</strong>をクリックします</li><li>モーダルが開きます（タイトル：「テーブルを編集」）</li><li>以下のフィールドを変更できます</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>説明</th></tr></thead><tbody><tr><td>テーブルコード</td><td>テキスト入力</td><td>新しいコードに変更可能</td></tr><tr><td>座席数</td><td>数値入力</td><td>定員の変更</td></tr><tr><td>有効</td><td>チェックボックス</td><td>チェックを外すとテーブルが無効になり、フロアマップやセルフオーダーに表示されなくなります</td></tr></tbody></table><ol start="4"><li>「保存」ボタンをクリックします</li><li>成功すると「テーブルを更新しました」トーストが表示されます</li></ol><h3 id="テーブルの削除" tabindex="-1">テーブルの削除 <a class="header-anchor" href="#テーブルの削除" aria-label="Permalink to &quot;テーブルの削除&quot;">​</a></h3><ol><li>一覧で対象テーブルの<strong>削除ボタン</strong>をクリックします</li><li>確認ダイアログが表示されます：「「T01」を削除しますか？」</li><li>「OK」をクリックすると削除されます</li><li>成功すると「テーブルを削除しました」トーストが表示されます</li></ol><div class="danger custom-block"><p class="custom-block-title">注意</p><p>テーブルを削除すると、そのテーブルに紐づく注文履歴やセッション履歴も影響を受けます（外部キー制約によるカスケード削除）。過去データを残したい場合は、削除ではなく「無効」に設定することを推奨します。</p></div><h3 id="qrコードの表示" tabindex="-1">QRコードの表示 <a class="header-anchor" href="#qrコードの表示" aria-label="Permalink to &quot;QRコードの表示&quot;">​</a></h3><p>各テーブルにはセルフオーダー用のQRコードが生成できます。</p><ol><li>一覧で対象テーブルの<strong>QRボタン</strong>をクリックします</li><li>モーダルが開きます（タイトル：「T01 QRコード」）</li><li>QRコード画像（200×200ピクセル）が表示されます</li><li>QRコードの下にURLが表示されます</li><li>「閉じる」ボタンでモーダルを閉じます</li></ol><p><strong>QRコードのURL形式：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/public/customer/menu.html?store_id=店舗ID&amp;table_id=テーブルID</span></span></code></pre></div><p>お客さんがこのQRコードをスマートフォンのカメラで読み取ると、そのテーブル専用のセルフオーダー画面が開きます。</p><div class="tip custom-block"><p class="custom-block-title">QRコードの活用方法</p><ul><li>印刷してテーブルに貼付する</li><li>アクリルスタンドに入れてテーブルに設置する</li><li>テーブルごとに異なるQRコードが生成されるため、注文がどのテーブルからのものかを自動的に識別できます</li></ul></div><p><strong>セッショントークンについて：</strong> QRコードにはテーブルのセッショントークンが紐づいています。トークンは以下のタイミングで自動更新されます。</p><ul><li>テーブル作成時（4時間の有効期限付き）</li><li>お客さんの会計完了時（精算処理でトークンが再生成される）</li><li>着席キャンセル時（セッション強制終了でトークンが再生成される）</li></ul><p>これにより、前のお客さんのQRコードでは次のお客さんが注文できないようになっています。</p><hr><h2 id="_5-2-フロアマップ" tabindex="-1">5.2 フロアマップ <a class="header-anchor" href="#_5-2-フロアマップ" aria-label="Permalink to &quot;5.2 フロアマップ&quot;">​</a></h2><h3 id="フロアマップ画面の構成" tabindex="-1">フロアマップ画面の構成 <a class="header-anchor" href="#フロアマップ画面の構成" aria-label="Permalink to &quot;フロアマップ画面の構成&quot;">​</a></h3><p>「テーブル・フロア」タブ → 「フロアマップ」サブタブを選択すると、リアルタイムのテーブル状況一覧が表示されます。</p><p><strong>データは5秒ごとに自動更新されます。</strong> 他のタブに切り替えると自動更新（ポーリング）は停止し、フロアマップタブに戻ると再開します。</p><h3 id="サマリーバー" tabindex="-1">サマリーバー <a class="header-anchor" href="#サマリーバー" aria-label="Permalink to &quot;サマリーバー&quot;">​</a></h3><p>画面上部にはテーブル状況のサマリーが表示されます。</p><table tabindex="0"><thead><tr><th>項目</th><th>表示例</th><th>説明</th></tr></thead><tbody><tr><td>全テーブル数</td><td>「全 12卓」</td><td>有効なテーブルの総数</td></tr><tr><td>空き</td><td>「空き 3」（緑色）</td><td>使用中でないテーブル数</td></tr><tr><td>使用中</td><td>「使用中 7」（青色）</td><td>セッションがあるテーブル数</td></tr><tr><td>未注文</td><td>「未注文 2」（オレンジ色）</td><td>着席しているが注文がまだないテーブル数（0の場合は非表示）</td></tr><tr><td>合計人数</td><td>「合計 28名」</td><td>現在の全テーブルのゲスト合計</td></tr><tr><td>合計売上</td><td>「¥42,000」（太字）</td><td>現在の全テーブルの未会計注文合計</td></tr><tr><td>ラストオーダー状態</td><td>「ラストオーダー中」（赤色）/ 「LO 22:00」（灰色）</td><td>ラストオーダーの状態</td></tr><tr><td>ラストオーダーボタン</td><td>「ラストオーダー」/「LO解除」</td><td>ラストオーダーを手動で発動/解除</td></tr></tbody></table><h3 id="テーブルカードの表示内容" tabindex="-1">テーブルカードの表示内容 <a class="header-anchor" href="#テーブルカードの表示内容" aria-label="Permalink to &quot;テーブルカードの表示内容&quot;">​</a></h3><p>各テーブルはカード形式で表示されます。テーブルの状態に応じてカードの左ボーダーと背景色が変わります。</p><h4 id="テーブルステータスと色分け" tabindex="-1">テーブルステータスと色分け <a class="header-anchor" href="#テーブルステータスと色分け" aria-label="Permalink to &quot;テーブルステータスと色分け&quot;">​</a></h4><table tabindex="0"><thead><tr><th>ステータス</th><th>色</th><th>バッジ</th><th>条件</th></tr></thead><tbody><tr><td>空き</td><td>緑（#43a047）</td><td>空き</td><td>セッションなし、注文なし</td></tr><tr><td>着席</td><td>青（#1e88e5）</td><td>着席</td><td>セッションあり、ステータス=seated</td></tr><tr><td>未注文</td><td>オレンジ（#ff9800）</td><td>未注文</td><td>seated だが注文が0件</td></tr><tr><td>食事中</td><td>濃い青（#1565c0）</td><td>食事中</td><td>ステータス=eating または注文あり</td></tr><tr><td>会計待ち</td><td>赤（#e53935）</td><td>会計待ち</td><td>ステータス=bill_requested</td></tr><tr><td>時間超過</td><td>濃いオレンジ（#e65100）</td><td>時間超過</td><td>経過時間 &gt; 制限時間（食べ放題プラン）</td></tr></tbody></table><h4 id="カードに表示される情報" tabindex="-1">カードに表示される情報 <a class="header-anchor" href="#カードに表示される情報" aria-label="Permalink to &quot;カードに表示される情報&quot;">​</a></h4><p><strong>空きテーブルの場合：</strong></p><ul><li>テーブルコード</li><li>「空き」バッジ（緑色）</li><li>座席数（「4名」）</li></ul><p><strong>使用中テーブルの場合：</strong></p><ul><li>テーブルコード</li><li>ステータスバッジ（色分け）</li><li>ゲスト数（「4名」）</li><li>経過時間（「25分経過」）</li><li>残り時間（食べ放題プラン適用時）：「残り65分」 <ul><li>時間超過の場合は赤文字で「5分超過」</li></ul></li><li>注文件数（「2件の注文」）</li><li>合計金額（「¥4,200」）</li><li>調理進捗バー（後述）</li><li>メモ（設定されている場合）</li><li>「メモ」ボタン</li><li>「取消」ボタン</li></ul><h4 id="調理進捗バー" tabindex="-1">調理進捗バー <a class="header-anchor" href="#調理進捗バー" aria-label="Permalink to &quot;調理進捗バー&quot;">​</a></h4><p>使用中テーブルのカードには、注文品の調理状況を示す横棒グラフが表示されます。4色のセグメントで構成されています。</p><table tabindex="0"><thead><tr><th>セグメント</th><th>色</th><th>意味</th></tr></thead><tbody><tr><td>提供済</td><td>—</td><td>お客さんに提供完了</td></tr><tr><td>完成</td><td>—</td><td>調理完了、提供待ち</td></tr><tr><td>調理中</td><td>—</td><td>現在調理中</td></tr><tr><td>受付</td><td>—</td><td>注文受付、調理未開始</td></tr></tbody></table><p>各セグメントにマウスを合わせると「提供済 3品」「調理中 1品」などのツールチップが表示されます。</p><h3 id="ラストオーダー機能" tabindex="-1">ラストオーダー機能 <a class="header-anchor" href="#ラストオーダー機能" aria-label="Permalink to &quot;ラストオーダー機能&quot;">​</a></h3><p>ラストオーダーは、セルフオーダー画面での新規注文をブロックする機能です。</p><p><strong>ラストオーダーの発動：</strong></p><ol><li>サマリーバーの「ラストオーダー」ボタンをクリックします</li><li>確認ダイアログが表示されます：「ラストオーダーを発動しますか？\\nセルフオーダー画面で注文がブロックされます。」</li><li>「OK」をクリックすると発動します</li><li>ボタンが赤色の「LO解除」に変わります</li><li>サマリーバーに「ラストオーダー中」が赤色で表示されます</li><li>お客さんのセルフオーダー画面で新規注文ができなくなります</li></ol><p><strong>ラストオーダーの解除：</strong></p><ol><li>赤色の「LO解除」ボタンをクリックします</li><li>確認ダイアログが表示されます：「ラストオーダーを解除しますか？」</li><li>「OK」をクリックすると解除されます</li><li>ボタンが通常の「ラストオーダー」に戻ります</li></ol><div class="info custom-block"><p class="custom-block-title">自動ラストオーダー</p><p>店舗設定でラストオーダー時刻を設定している場合（例：22:00）、設定時刻になると自動的にラストオーダーが発動します。手動ボタンは、設定時刻に関わらずいつでも発動/解除できます。</p></div><h3 id="メモ機能" tabindex="-1">メモ機能 <a class="header-anchor" href="#メモ機能" aria-label="Permalink to &quot;メモ機能&quot;">​</a></h3><p>テーブルセッションにメモを追加できます。アレルギー情報やVIP対応など、スタッフ間の情報共有に使います。</p><p><strong>メモの追加・編集：</strong></p><ol><li>テーブルカードの「メモ」ボタンをクリックします</li><li>メモモーダルが開きます（タイトル：「T01 メモ」）</li><li>6つのプリセットタグが表示されます</li></ol><table tabindex="0"><thead><tr><th>プリセットタグ</th></tr></thead><tbody><tr><td>アレルギー注意</td></tr><tr><td>VIP</td></tr><tr><td>お子様連れ</td></tr><tr><td>誕生日</td></tr><tr><td>接待</td></tr><tr><td>車椅子</td></tr></tbody></table><ol start="4"><li>プリセットタグをクリックすると、テキストエリアにタグが追記されます（改行区切り）</li><li>自由にテキストを入力することもできます</li><li>「保存」ボタンをクリックします</li><li>保存中はボタンが「保存中...」に変わり無効化されます</li><li>成功するとモーダルが閉じ、テーブルカードにメモが表示されます</li></ol><p>メモはテーブルカードの下部に灰色のテキストとして表示され、スタッフ全員が確認できます。</p><h3 id="着席のキャンセル" tabindex="-1">着席のキャンセル <a class="header-anchor" href="#着席のキャンセル" aria-label="Permalink to &quot;着席のキャンセル&quot;">​</a></h3><p>テーブルの着席（セッション）を強制的に終了させます。</p><ol><li>テーブルカードの「取消」ボタンをクリックします</li><li>確認ダイアログが表示されます：「T01 の着席をキャンセルしますか？」</li><li>「OK」をクリックすると以下が実行されます <ul><li>セッションが「closed」ステータスに変更されます</li><li>そのテーブルの未会計の注文が全て「cancelled」ステータスに変更されます</li><li>テーブルのセッショントークンが再生成されます（古いQRコードが無効になります）</li></ul></li><li>テーブルカードが「空き」状態に戻ります</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>着席キャンセルは未会計の注文を全てキャンセルします。既に調理済みの料理がある場合は、先に会計処理を行ってからキャンセルしてください。</p></div><hr><h2 id="_5-3-テーブルセッション" tabindex="-1">5.3 テーブルセッション <a class="header-anchor" href="#_5-3-テーブルセッション" aria-label="Permalink to &quot;5.3 テーブルセッション&quot;">​</a></h2><p>テーブルセッションとは、お客さんが着席してから会計が完了するまでの一連の流れを管理するデータです。</p><h3 id="セッションのライフサイクル" tabindex="-1">セッションのライフサイクル <a class="header-anchor" href="#セッションのライフサイクル" aria-label="Permalink to &quot;セッションのライフサイクル&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>着席（seated） → 食事中（eating） → 会計待ち（bill_requested） → 支払済（paid） → 終了（closed）</span></span></code></pre></div><p>各ステータスの意味は以下のとおりです。</p><table tabindex="0"><thead><tr><th>ステータス</th><th>意味</th><th>遷移タイミング</th></tr></thead><tbody><tr><td>seated</td><td>着席済み</td><td>ハンディPOSやフロアマップから着席操作した時</td></tr><tr><td>eating</td><td>食事中</td><td>注文が入った時</td></tr><tr><td>bill_requested</td><td>会計待ち</td><td>お客さんが会計をリクエストした時</td></tr><tr><td>paid</td><td>支払済み</td><td>レジで会計が完了した時</td></tr><tr><td>closed</td><td>終了</td><td>支払い後にセッションが閉じられた時、または着席キャンセル時</td></tr></tbody></table><h3 id="セッションに記録される情報" tabindex="-1">セッションに記録される情報 <a class="header-anchor" href="#セッションに記録される情報" aria-label="Permalink to &quot;セッションに記録される情報&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情報</th><th>説明</th></tr></thead><tbody><tr><td>ゲスト数</td><td>着席人数</td></tr><tr><td>開始日時</td><td>着席した日時</td></tr><tr><td>終了日時</td><td>会計完了または強制終了した日時</td></tr><tr><td>プラン</td><td>食べ放題プランを選択した場合（プランID、制限時間、ラストオーダー時間、有効期限）</td></tr><tr><td>コース</td><td>コース料理を選択した場合（コースID、現在のフェーズ番号、フェーズ開始日時）</td></tr><tr><td>メモ</td><td>テーブルメモ（アレルギー情報、VIP等）</td></tr></tbody></table><h3 id="食べ放題プラン選択時の動作" tabindex="-1">食べ放題プラン選択時の動作 <a class="header-anchor" href="#食べ放題プラン選択時の動作" aria-label="Permalink to &quot;食べ放題プラン選択時の動作&quot;">​</a></h3><p>着席時に食べ放題プランを選択すると、以下が自動計算されます。</p><ul><li><strong>有効期限</strong> = 着席日時 + プランの制限時間（例：90分）</li><li><strong>ラストオーダー期限</strong> = 着席日時 + （制限時間 − ラストオーダー閾値）（例：90分 − 15分 = 75分後）</li></ul><p>フロアマップのテーブルカードでは残り時間がカウントダウン表示され、制限時間を超えると「時間超過」ステータスになります。</p><h3 id="コース料理選択時の動作" tabindex="-1">コース料理選択時の動作 <a class="header-anchor" href="#コース料理選択時の動作" aria-label="Permalink to &quot;コース料理選択時の動作&quot;">​</a></h3><p>着席時にコース料理を選択すると、以下が自動で行われます。</p><ol><li>現在のフェーズが「フェーズ1」に設定されます</li><li>フェーズ1に含まれる料理が自動的に注文されます（数量はコース定義に従い、価格は0円）</li><li>KDS（キッチンディスプレイ）にフェーズ1の料理が表示されます</li><li>フェーズの進行はKDS画面から「次フェーズ」ボタンで操作します</li></ol><div class="info custom-block"><p class="custom-block-title">プランとコースの排他制御</p><p>食べ放題プランとコース料理は同時に選択できません。着席時にどちらか一方を選択するか、どちらも選択しない（通常のアラカルト注文）かを選びます。</p></div><hr><h2 id="_5-4-フロアマップのデータ構造" tabindex="-1">5.4 フロアマップのデータ構造 <a class="header-anchor" href="#_5-4-フロアマップのデータ構造" aria-label="Permalink to &quot;5.4 フロアマップのデータ構造&quot;">​</a></h2><p>各テーブルは以下のフロアマップ用データを持っています。APIのPATCHリクエストで更新できます。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th><th>初期値</th></tr></thead><tbody><tr><td>pos_x</td><td>X座標（ピクセル）</td><td>0</td></tr><tr><td>pos_y</td><td>Y座標（ピクセル）</td><td>0</td></tr><tr><td>width</td><td>幅（ピクセル）</td><td>80</td></tr><tr><td>height</td><td>高さ（ピクセル）</td><td>80</td></tr><tr><td>shape</td><td>形状（rect / circle / ellipse）</td><td>rect</td></tr><tr><td>floor</td><td>フロア名（1F / 2F / テラス 等）</td><td>1F</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">フロアマップのドラッグ配置</p><p>現在のフロアマップはカード一覧形式で表示されています。ドラッグ＆ドロップによるビジュアルなテーブル配置機能は、上記のデータ構造（座標・サイズ・形状）が準備されており、今後のアップデートで実装予定です。</p></div>',94)])])}const u=d(r,[["render",e]]);export{c as __pageData,u as default};
